  create policy "User can select sentence."
  on "public"."sentence_list"
  as permissive
  for select
  to authenticated
using ((( SELECT auth.uid() AS uid) = uid));



  create policy "Users can create a sentence."
  on "public"."sentence_list"
  as permissive
  for insert
  to authenticated
with check ((( SELECT auth.uid() AS uid) = uid));



  create policy "Users can delete a sentence."
  on "public"."sentence_list"
  as permissive
  for delete
  to authenticated
using ((( SELECT auth.uid() AS uid) = uid));



  create policy "User can select there data"
  on "public"."user"
  as restrictive
  for select
  to authenticated
using (( SELECT (auth.uid() = "user".uid)));



  create policy "Users can create a word."
  on "public"."word_list"
  as permissive
  for insert
  to authenticated
with check ((( SELECT auth.uid() AS uid) = uid));



  create policy "Users can delete a word."
  on "public"."word_list"
  as permissive
  for delete
  to authenticated
using ((( SELECT auth.uid() AS uid) = uid));



  create policy "Users can update isSentence boolean."
  on "public"."word_list"
  as permissive
  for update
  to authenticated
using ((( SELECT auth.uid() AS uid) = uid))
with check ((( SELECT auth.uid() AS uid) = uid));



  create policy "user can select there own word"
  on "public"."word_list"
  as permissive
  for select
  to authenticated
using ((( SELECT auth.uid() AS uid) = uid));


CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();


  create policy "User can delete their images"
  on "storage"."objects"
  as permissive
  for delete
  to authenticated
using (((bucket_id = 'images'::text) AND (owner_id = ( SELECT (auth.uid())::text AS uid))));



  create policy "User can insert their files"
  on "storage"."objects"
  as permissive
  for insert
  to authenticated
with check (((bucket_id = 'images'::text) AND ((storage.foldername(name))[1] = (( SELECT auth.uid() AS uid))::text)));



  create policy "User can view their files"
  on "storage"."objects"
  as permissive
  for select
  to authenticated
using (((bucket_id = 'images'::text) AND ((storage.foldername(name))[1] = (( SELECT auth.uid() AS uid))::text)));



